export interface AgentEvent {
    id: string;
    data: {
        datasetId: string;
        action: "modify";
    };
    createdAt: string;
}
/**
 * Continuously poll the dataset's agent-event channel and invoke `onEvent`
 * for each new event the server hands us. Each poll request is short-lived
 * (Vercel-friendly): no SSE, no long-poll, just a normal GET that returns
 * any newly-claimed `dataset.agent.event` tickets since the last cursor.
 *
 * The loop runs until `abortSignal` fires. Network errors are swallowed and
 * retried on the next tick — transient connectivity should not surface as a
 * fatal terminal-channel close, since `startDataset.ts` listens to a separate
 * (terminal) channel for the user clicking Done.
 */
export declare function pollAgentEvents(opts: {
    serviceUrl: string;
    apiKey: string;
    datasetId: string;
    intervalMs?: number;
    /**
     * ISO timestamp to start polling after — events with createdAt strictly
     * greater than this are returned. Empty string or undefined polls from
     * the beginning (server-side default), which is what fresh sessions want.
     * Resume sessions pass the persisted cursor so already-seen events
     * aren't replayed.
     */
    startCursor?: string;
    abortSignal: AbortSignal;
    onEvent: (event: AgentEvent) => void;
    onError?: (err: Error) => void;
}): Promise<void>;
